def solve(well_type, depth, length=None):
    if well_type == 'vertical':
        return f"Drilling a vertical well to {depth} meters."
    elif well_type == 'horizontal':
        if length is None:
            raise ValueError("Length must be provided for horizontal wells.")
        return f"Drilling a horizontal well to {depth} meters with a length of {length} meters."
    else:
        raise ValueError("Invalid well type. Must be 'vertical' or 'horizontal'.")
